/**
 * 浏览器指纹 —— 主编排模块
 *
 * 职责：
 *  1. 收集各子模块的指纹特征，汇总为完整的浏览器指纹对象
 *  2. 对原始指纹 JSON 提取稳定特征，组合 IP / UA 等生成设备唯一 ID
 *
 * 子模块拆分于 ./fingerprint/ 目录：
 *  - hash       哈希工具
 *  - canvas     Canvas 指纹
 *  - audio      音频指纹
 *  - webgl      WebGL 检测
 *  - fonts      字体检测
 *  - deviceInfo 设备 & OS 信息
 *  - capabilities  浏览器能力检测
 *  - media      插件 / MIME / 媒体设备
 *  - css        CSS 特征指纹
 *  - performance  性能 & 内存
 */
/**
 * 采集增强的浏览器指纹信息
 *
 * 汇总所有子模块的检测结果，返回一个包含浏览器、屏幕、设备、
 * 能力、Canvas / WebGL / 音频 / 字体 / 插件 / CSS / 性能等
 * 维度数据的对象。
 *
 * @returns 完整的浏览器指纹对象
 */
export declare const getBrowserFingerprint: () => Promise<Record<string, unknown>>;
